import { useFocusEffect, useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useCallback, useContext, useMemo, useState } from 'react';
import { Alert, Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import { AuthContext } from '../../App';
import CustomerBottomNav from '../components/CustomerBottomNav';
import OrderHistoryCard from '../components/OrderHistoryCard';
import { RootStackParamList } from '../navigation/AppNavigator';
import { cancelOrder, fetchCustomerOrders, OrderRecord } from '../services/firebaseService';

type FilterKey = 'Active' | 'Delivered' | 'Cancelled';
type NavigationProp = NativeStackNavigationProp<RootStackParamList, 'CustomerOrders'>;

const filters: FilterKey[] = ['Active', 'Delivered', 'Cancelled'];

const CustomerOrdersScreen = () => {
  const { profile } = useContext(AuthContext);
  const navigation = useNavigation<NavigationProp>();
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [selectedFilter, setSelectedFilter] = useState<FilterKey>('Active');

  const loadOrders = useCallback(async () => {
    if (!profile?.uid) {
      setOrders([]);
      return;
    }
    const data = await fetchCustomerOrders(profile.uid).catch(() => []);
    setOrders(data);
  }, [profile?.uid]);

  useFocusEffect(
    useCallback(() => {
      loadOrders();
    }, [loadOrders])
  );

  const filteredOrders = useMemo(() => {
    switch (selectedFilter) {
      case 'Delivered':
        return orders.filter((order) => order.status === 'delivered');
      case 'Cancelled':
        return orders.filter((order) => order.status === 'cancelled');
      default:
        return orders.filter((order) => order.status !== 'delivered' && order.status !== 'cancelled');
    }
  }, [orders, selectedFilter]);

  const activeOrders = orders.filter((order) => order.status !== 'delivered' && order.status !== 'cancelled');
  const historyOrders = orders.filter((order) => order.status === 'delivered' || order.status === 'cancelled');

  const handleCancel = (order: OrderRecord) => {
    Alert.alert('Cancel order', 'Are you sure you want to cancel this order?', [
      { text: 'No' },
      {
        text: 'Yes, cancel',
        style: 'destructive',
        onPress: async () => {
          await cancelOrder(order.id!);
          loadOrders();
        }
      }
    ]);
  };

  const renderOrders = (items: OrderRecord[]) => {
    if (!items.length) {
      return (
        <View style={styles.emptyCard}>
          <Text style={styles.emptyTitle}>No orders in this section</Text>
          <Text style={styles.emptyText}>Your active and previous deliveries will appear here.</Text>
        </View>
      );
    }

    return items.map((order) => (
      <View key={order.id} style={styles.orderWrap}>
        <OrderHistoryCard
          order={order}
          onViewDetails={() => navigation.navigate('OrderDetails', { orderId: order.id! })}
          onTrack={() => navigation.navigate('OrderTracking', { orderId: order.id })}
          onReorder={() => navigation.navigate('NewOrder', { reorder: true })}
          onCancel={() => handleCancel(order)}
          onModify={() => navigation.navigate('NewOrder', { orderId: order.id })}
        />
      </View>
    ));
  };

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <Text style={styles.title}>My Orders</Text>
        <Text style={styles.subtitle}>View current orders, previous deliveries, and reorder quickly.</Text>

        <View style={styles.filterRow}>
          {filters.map((filter) => {
            const selected = filter === selectedFilter;
            return (
              <Pressable
                key={filter}
                style={[styles.filterChip, selected && styles.filterChipSelected]}
                onPress={() => setSelectedFilter(filter)}
              >
                <Text style={[styles.filterChipText, selected && styles.filterChipTextSelected]}>{filter}</Text>
              </Pressable>
            );
          })}
        </View>

        <View style={styles.summaryRow}>
          <View style={styles.summaryCard}>
            <Text style={styles.summaryLabel}>Active</Text>
            <Text style={styles.summaryValue}>{activeOrders.length}</Text>
          </View>
          <View style={styles.summaryCard}>
            <Text style={styles.summaryLabel}>History</Text>
            <Text style={styles.summaryValue}>{historyOrders.length}</Text>
          </View>
        </View>

        <View style={styles.section}>
          <Text style={styles.sectionTitle}>{selectedFilter} Orders</Text>
          {renderOrders(filteredOrders)}
        </View>
      </ScrollView>
      <CustomerBottomNav active="CustomerOrders" />
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F2F9FF'
  },
  content: {
    padding: 18,
    paddingBottom: 110
  },
  title: {
    color: '#10324A',
    fontSize: 28,
    fontWeight: '900'
  },
  subtitle: {
    marginTop: 8,
    color: '#5E788C',
    fontSize: 14,
    lineHeight: 21
  },
  filterRow: {
    marginTop: 18,
    flexDirection: 'row',
    gap: 10
  },
  filterChip: {
    flex: 1,
    borderRadius: 18,
    backgroundColor: 'white',
    paddingVertical: 12,
    alignItems: 'center'
  },
  filterChipSelected: {
    backgroundColor: '#0D8DD8'
  },
  filterChipText: {
    color: '#0D63A8',
    fontSize: 14,
    fontWeight: '800'
  },
  filterChipTextSelected: {
    color: 'white'
  },
  summaryRow: {
    marginTop: 16,
    flexDirection: 'row',
    gap: 12
  },
  summaryCard: {
    flex: 1,
    backgroundColor: 'white',
    borderRadius: 22,
    padding: 16
  },
  summaryLabel: {
    color: '#67839A',
    fontSize: 12,
    fontWeight: '700'
  },
  summaryValue: {
    marginTop: 8,
    color: '#10324A',
    fontSize: 26,
    fontWeight: '900'
  },
  section: {
    marginTop: 18
  },
  sectionTitle: {
    color: '#10324A',
    fontSize: 19,
    fontWeight: '800',
    marginBottom: 12
  },
  orderWrap: {
    marginBottom: 14
  },
  emptyCard: {
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 18
  },
  emptyTitle: {
    color: '#10324A',
    fontSize: 18,
    fontWeight: '800'
  },
  emptyText: {
    marginTop: 8,
    color: '#6D8699',
    fontSize: 14,
    lineHeight: 20
  }
});

export default CustomerOrdersScreen;
